package com.restaurantcraft.blockentity; import com.restaurantcraft.menu.CookingDeviceMenu; import com.restaurantcraft.registry.ModBlockEntities; import net.minecraft.core.*; import net.minecraft.nbt.CompoundTag; import net.minecraft.network.chat.Component; import net.minecraft.server.level.ServerPlayer; import net.minecraft.world.*; import net.minecraft.world.entity.player.*; import net.minecraft.world.inventory.AbstractContainerMenu; import net.minecraft.world.item.*; import net.minecraft.world.level.block.entity.*; import net.minecraft.world.level.block.state.BlockState; import net.minecraftforge.common.capabilities.*; import net.minecraftforge.common.util.LazyOptional; import net.minecraftforge.items.*; import net.minecraftforge.network.NetworkHooks; import org.jetbrains.annotations.Nullable; public class SinkBlockEntity extends BlockEntity implements MenuProvider { public final ItemStackHandler items=new ItemStackHandler(2){protected void onContentsChanged(int s){setChanged();}}; private final LazyOptional<IItemHandler> cap=LazyOptional.of(()->items); public int progress; public SinkBlockEntity(BlockPos p, BlockState s){super(ModBlockEntities.SINK.get(),p,s);} public Component getDisplayName(){return Component.translatable("block.restaurant_craft.sink");} @Nullable public AbstractContainerMenu createMenu(int id, Inventory inv, Player p){return new CookingDeviceMenu(id,inv,this);} public void openMenu(ServerPlayer sp){NetworkHooks.openScreen(sp,this,worldPosition);} public void tick(){ if(level==null||level.isClientSide)return; ItemStack in=items.getStackInSlot(0),out=items.getStackInSlot(1); ItemStack result=ItemStack.EMPTY; int max=0; if(in.is(Items.BUCKET)){result=new ItemStack(Items.WATER_BUCKET);max=100;} if(in.is(Items.GLASS_BOTTLE)){result=new ItemStack(Items.POTION);max=40;} if(result.isEmpty()||(!out.isEmpty()&&!ItemStack.isSameItemSameTags(out,result))){progress=0;return;} if(++progress>=max){if(out.isEmpty())items.setStackInSlot(1,result);else out.grow(1);in.shrink(1);progress=0;setChanged();}} protected void saveAdditional(CompoundTag t){super.saveAdditional(t);t.put("Items",items.serializeNBT());t.putInt("Progress",progress);} public void load(CompoundTag t){super.load(t);items.deserializeNBT(t.getCompound("Items"));progress=t.getInt("Progress");} public <T> LazyOptional<T> getCapability(Capability<T> c, Direction d){return c==ForgeCapabilities.ITEM_HANDLER?cap.cast():super.getCapability(c,d);} public void invalidateCaps(){super.invalidateCaps();cap.invalidate();} }
